
import binascii
import struct

def parse_wkb(hex_str):
    # WKB structure roughly:
    # 1 byte: endianness (01 = little)
    # 4 bytes: geometry type
    # If SRID flag set (e.g. 0x20000000), 4 bytes SRID follow
    # Then geometry data...
    
    data = binascii.unhexlify(hex_str)
    
    # Check endianness
    order = '<' if data[0] == 1 else '>'
    
    # Read type
    geom_type = struct.unpack(order + 'I', data[1:5])[0]
    
    offset = 5
    
    # Check for SRID (assuming EWKB from PostGIS often has it)
    # MultiPolygon is 6. With SRID it might involve flags in higher bits or be extended type.
    # PostGIS EWKB: SRID flag is 0x20000000.
    srid = None
    if geom_type & 0x20000000:
        srid = struct.unpack(order + 'I', data[offset:offset+4])[0]
        offset += 4
        geom_type &= ~0x20000000
        
    coords_list = []

    if geom_type == 6: # MultiPolygon
        num_polys = struct.unpack(order + 'I', data[offset:offset+4])[0]
        offset += 4
        for _ in range(num_polys):
            # Read Polygon
            # 1 byte order + 4 bytes type (Polygon=3)
            # We assume sub-geometries inherit endianness/type structure usually, 
            # but standard WKB puts them there.
            sub_order_b = data[offset]
            sub_order = '<' if sub_order_b == 1 else '>'
            offset += 1
            sub_type = struct.unpack(sub_order + 'I', data[offset:offset+4])[0]
            offset += 4
            
            if sub_type != 3:
                print(f"Unexpected subtype {sub_type}")
                return
                
            num_rings = struct.unpack(sub_order + 'I', data[offset:offset+4])[0]
            offset += 4
            
            poly_coords = []
            for _ in range(num_rings):
                num_points = struct.unpack(sub_order + 'I', data[offset:offset+4])[0]
                offset += 4
                ring = []
                for _ in range(num_points):
                    x, y = struct.unpack(sub_order + 'dd', data[offset:offset+16])
                    offset += 16
                    ring.append((x, y))
                poly_coords.append(ring)
            coords_list.append(poly_coords)
            
    return coords_list

